let tokenMap = {}

function isCSSVarEnabled(context) {
  return context.frames.some((frame) => {
    const variable = frame.variables()['@theme-css-variable-enabled']
    return variable ? variable.value.eval(context).value === 'true' : false
  })
}

module.exports = {
  install: function (less, pluginManager, functions) {
    functions.add('theme-css-variables', function (selector) {
      return isCSSVarEnabled(this.context)
        ? new less.tree.Ruleset(
            [new less.tree.Selector(selector ? selector.value : ':root')],
            Object.entries(tokenMap).map(
              ([name, value]) => new less.tree.Declaration(name, value),
            ),
          )
        : false
    })
    functions.add('theme', function (...args) {
      const ret = new less.tree.Value(args.slice(1)).eval(this.context)
      if (args[0].args && args[0].name === 'var') {
        const cssCuzProp = args[0].args[0].value
        tokenMap[cssCuzProp] = ret
      }
      return isCSSVarEnabled(this.context) ? args[0] : ret
    })
  },
}
